const SQL = await initSqlJs();
const db = new SQL.Database();
db.run(`
  CREATE TABLE IF NOT EXISTS games (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT,
    header_image TEXT,
    short_description TEXT,
    tags TEXT,
    genres TEXT,
    platforms TEXT,
    release_date TEXT,
    rating REAL,
    total_reviews INTEGER,
    positive_ratio INTEGER,
    has_chinese INTEGER DEFAULT 0,
    metacritic INTEGER DEFAULT 0,
    source TEXT DEFAULT 'seed'
  )
`);

const stmt = db.prepare("INSERT INTO games (name, tags, genres, platforms, release_date, rating, total_reviews, positive_ratio, has_chinese, metacritic, source) VALUES (?,?,?,?,?,?,?,?,?,?,?)");
for (const g of GAMES) {
  stmt.run([g.name, g.tags, g.genres, g.platforms, g.release_date, g.rating, g.total_reviews, g.positive_ratio, g.has_chinese, g.metacritic, 'seed']);
}
stmt.free();

const data = db.export();
fs.writeFileSync(path.join(dataDir, 'games.db'), Buffer.from(data));
db.close();
console.log(`Done: ${GAMES.length} games seeded to data/games.db`);
